import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"斑纹","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/斑纹.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/斑纹.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/斑纹.md"};function p(l,a,i,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"斑纹",tabindex:"-1"},[s("斑纹 "),e("a",{class:"header-anchor",href:"#斑纹","aria-label":'Permalink to "斑纹"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="斑纹-1" tabindex="-1">斑纹 <a class="header-anchor" href="#斑纹-1" aria-label="Permalink to &quot;斑纹&quot;">​</a></h1><p>斑纹（4）<br> 价格：12专长点<br> 前置：全集中呼吸-常中<br> 出自《鬼灭之刃》，只有在呼吸法使用达到极致之时，使自己的心跳达到200次/秒，体温超过39℃的状态下能够觉醒的力量。开启斑纹之后根据持有者使用的呼吸法和个人特质会在体表出现一道特殊的花纹（如研习兽之呼吸的人，将会出现兽牙状的斑纹），能够大幅度提升使用者的战斗能力，即使面对上弦之鬼也有足够匹敌的一战之力，乃至在某些方面上些许超过。</p><p>副作用是斑纹会预支生命力，绝大部分开启者都活不过25岁，但也许在一些强大的体质下能够避免英年早逝的结果。</p><p>斑纹需要使用者在至少消耗等同于你耐力属性等级/2点的呼吸法时才能够开启，以一个自由动作激活，接下来一场景内你进行的生理相关检定获得等同于你平均生理属性等级/2的增强加值，当斑纹处于开启状态时，哪怕你的伤势已经将严重填满也不会陷入昏迷，你的移动速度临时增加40米。</p><p>在强化斑纹后，你的寿命上限将锁定于25岁，如果你年龄已经大于25岁，你将在斑纹强化完的12小时后寿尽死亡，这是一个C级创伤来源的衰老效果，但特殊的，强化者如果具有【不老】，【C级及以上的衰老效果免疫】，【C级及以上创伤来源效果免疫】，则该副作用将会被不生效。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
